delta_columns_pattern.delta_with_arrow_label:
// For a text delta column with arrow:
MoM Label =
VAR _Chg = [MoM Change %]
RETURN
    IF(ISBLANK(_Chg), "",
    IF(_Chg > 0, "▲ " & FORMAT(_Chg, "+0.0%"),
    IF(_Chg < 0, "▼ " & FORMAT(_Chg, "0.0%"),
    "→ 0.0%")))
// This is a text measure — useful for tooltip text but cannot be
// conditionally formatted as a number. Use the numeric [MoM Change %]
// for background color formatting.

grand_totals_behavior.overriding_grand_total_with_dax:
// To show a custom grand total (e.g. show the MAX instead of SUM across metrics):
Metric Value With Custom Total =
IF(
    ISINSCOPE(MetricDim[MetricName]),  -- inside a metric row
    SUM(SecuritySnapshots[Value]),      -- normal row calculation
    MAXX(VALUES(MetricDim[MetricName]), [Metric Value])  -- total row = max across metrics
)
// ISINSCOPE() returns TRUE when the specified column is in scope
// (i.e., the row has been grouped by MetricName)
